module Comparator_4bit(
  input  [3:0] A,
  input  [3:0] B,
  output A_greater_B,
  output A_equal_B,
  output A_less_B
);
  assign A_greater_B = (A > B);
  assign A_equal_B   = (A == B);
  assign A_less_B    = (A < B);
endmodule

module Comparator_4bit_bitwise(
  input  [3:0] A,
  input  [3:0] B,
  output reg A_greater_B,
  output reg A_equal_B,
  output reg A_less_B
);
  always @(A or B)
  begin
    A_greater_B = 0;
    A_equal_B   = 0;
    A_less_B    = 0;

    if (A > B)
      A_greater_B = 1;
    else if (A == B)
      A_equal_B = 1;
    else
      A_less_B = 1;
  end
endmodule

# Input A[3:0]
NET "A[0]" LOC="P22";
NET "A[1]" LOC="P21";
NET "A[2]" LOC="P17";
NET "A[3]" LOC="P16";

# Input B[3:0]
NET "B[0]" LOC="P15";
NET "B[1]" LOC="P14";
NET "B[2]" LOC="P12";
NET "B[3]" LOC="P11";

# Outputs
NET "A_greater_B" LOC="P138";
NET "A_equal_B"   LOC="P142";
NET "A_less_B"    LOC="P143";
